const input = $input.first().json || {};
const sshBase = 'ssh -i /home/node/.ssh/odin_os_ingress -o StrictHostKeyChecking=no -o ConnectTimeout=5 orchestrator@172.17.0.1';

function shellSingleQuote(value) {
  return "'" + String(value).replace(/'/g, "'\"'\"'") + "'";
}

function machineValue(value, field) {
  const normalized = String(value || '').trim();
  if (!normalized) {
    throw new Error(field + ' is required');
  }
  if (/\s/.test(normalized)) {
    throw new Error(field + ' must not contain whitespace');
  }
  return normalized;
}

const routerMode = String(input.router_mode || 'intake').trim();
if (routerMode === 'approval_resolve') {
  const approvalId = String(input.approval_id || '').trim();
  const decisionRaw = String(input.approval_decision || '').trim().toLowerCase();
  const decision = decisionRaw === 'deny' ? 'reject' : decisionRaw;
  const reason = String(input.approval_reason || 'telegram-callback').trim() || 'telegram-callback';
  const by = machineValue(input.approval_by || 'telegram', 'approval_by');

  if (!/^[0-9]+$/.test(approvalId)) {
    throw new Error('approval_id must be numeric');
  }
  if (!['approve', 'reject'].includes(decision)) {
    throw new Error('approval_decision must be approve or reject');
  }

  const routerCommand = 'approval-resolve ' + approvalId + ' ' + decision + ' ' + shellSingleQuote(reason);
  return [{ json: {
    router_mode: 'approval_resolve',
    approval_resolve: 'approval-resolve',
    approval_id: approvalId,
    approval_decision: decision,
    approval_reason: reason,
    approval_by: by,
    command: sshBase + ' ' + shellSingleQuote(routerCommand)
  } }];
}

const schemaVersion = Number(input.schema_version || 0);
if (schemaVersion !== 1) {
  throw new Error('schema_version must be 1');
}

const envelope = {
  schema_version: 1,
  source: machineValue(input.source, 'source'),
  type: machineValue(input.type, 'type'),
  project_key: machineValue(input.project_key, 'project_key'),
  title: String(input.title || '').trim(),
  action_key: String(input.action_key || '').trim(),
  dedup_key: String(input.dedup_key || '').trim(),
  requested_by: machineValue(input.requested_by || input.source, 'requested_by'),
  payload: input.payload || {}
};

if (!envelope.title) {
  throw new Error('title is required');
}
if (typeof envelope.payload !== 'object' || envelope.payload === null || Array.isArray(envelope.payload)) {
  throw new Error('payload must be a JSON object');
}

const envelopeB64 = Buffer.from(JSON.stringify(envelope)).toString('base64');
// Empty SSH_ORIGINAL_COMMAND routes stdin to odin intake enqueue through the forced command.
return [{ json: {
  ...envelope,
  router_mode: 'intake',
  envelope_b64: envelopeB64,
  command: 'printf %s ' + shellSingleQuote(envelopeB64) + ' | base64 -d | ' + sshBase
} }];
